import { lazy, Suspense, useCallback, useMemo } from 'react';
import Box from '@mui/material/Box';
import { CardSlider, Loader } from '@shared/ui';
import { useAppDispatch, useAppSelector } from '@shared/store';
import {
  DEFAULT_COLORS,
  type CharacterPart,
  MOCK_CHARACTER_PARTS,
  selectActivePartId,
  setActivePartId,
} from '@entities/character';
import { GenerateActions } from '@features/generate-character';
import styles from './GenerateDock.module.scss';

const LazyPartAttributeDrawer = lazy(() =>
  import('@features/generate-character/ui/PartAttributeDrawer/PartAttributeDrawer').then((m) => ({
    default: m.PartAttributeDrawer,
  })),
);

interface GenerateDockProps {
  /** Открыть sheet «Создать персонажа» (состояние на странице генерации). */
  onOpenCreate: () => void;
  /** Открыть подтверждение удаления драфта. */
  onOpenDelete: () => void;
}

const PartDrawerChunkFallback = () => (
  <Box
    className={styles.partDrawerFallback}
    aria-busy="true"
    aria-live="polite"
  >
    <Loader height={72} size={36} text="Загрузка редактора…" />
  </Box>
);

/**
 * Нижний док: выбор части тела и панель действий. Атрибуты и цвет — в ленивом дравере без затемнения превью.
 */
export const GenerateDock = ({ onOpenCreate, onOpenDelete }: GenerateDockProps) => {
  const dispatch = useAppDispatch();
  const activePartId = useAppSelector(selectActivePartId);

  const partIds = useMemo(() => MOCK_CHARACTER_PARTS.map((p) => p.id), []);
  const svgIds = useMemo(() => {
    const paths = Object.keys(import.meta.glob('@assets/images/*.svg'));
    return paths
      .map((path) => path.split('/').pop()?.replace('.svg', '') ?? '')
      .filter(Boolean)
      .sort((a, b) => Number(a) - Number(b));
  }, []);

  const handlePartSelect = useCallback(
    (id: string | null) => {
      dispatch(setActivePartId(id));
    },
    [dispatch],
  );

  const handleClosePartDrawer = useCallback(() => {
    dispatch(setActivePartId(null));
  }, [dispatch]);

  const renderPartItem = useCallback((item: CharacterPart) => item.label, []);

  return (
    <Box className={styles.dock} role="region" aria-label="Панель генерации персонажа">
      <CardSlider
        items={MOCK_CHARACTER_PARTS}
        selectedId={activePartId}
        onSelect={handlePartSelect}
        itemVariant="text"
        renderItem={renderPartItem}
      />

      {activePartId ? (
        <Suspense fallback={<PartDrawerChunkFallback />}>
          <LazyPartAttributeDrawer onClose={handleClosePartDrawer} />
        </Suspense>
      ) : null}

      <Box className={styles.actions}>
        <GenerateActions
          partIds={partIds}
          svgIds={svgIds}
          colors={DEFAULT_COLORS}
          onOpenCreate={onOpenCreate}
          onOpenDelete={onOpenDelete}
        />
      </Box>
    </Box>
  );
};
